+    #[test]
+    fn posterior_monotonic_convergence_on_stable() {
+        let mut strategy = BayesianDiffStrategy::new();
+        let mut prev_stable_prob = 0.25;
+        for i in 0..20 {
+            strategy.observe_with_ledger(&stable_frame(), None);
+            let post = strategy.posterior();
+            if i >= 2 {
+                assert!(
