+    #[test]
+    fn parse_long_key_is_truncated() {
+        let long_key = "x".repeat(5000);
+        let payload = serde_json::to_vec(&json!({
+            "type": "Input",
+            "data": {"kind": "Key", "key": long_key, "modifiers": 0}
